Example:
    >>> import jsonschema
    >>> schema = elem.OBJECT()
    >>> jsonschema.validate({}, schema)
    >>> #
    >>> import jsonschema
    >>> schema = elem.OBJECT({
    >>>     'key1': elem.ANY(),
    >>>     'key2': elem.ANY(),
    >>> }, required=['key1'])
    >>> jsonschema.validate({'key1': None}, schema)
    >>> #
    >>> import jsonschema
    >>> schema = elem.OBJECT({
    >>>     'key1': elem.OBJECT({'arr': elem.ARRAY()}),
    >>>     'key2': elem.ANY(),
    >>> }, required=['key1'], title='a title')
    >>> schema.validate()
    >>> print('schema = {}'.format(ub.urepr(schema, sort=1, nl=-1)))
    >>> jsonschema.validate({'key1': {'arr': []}}, schema)
    schema = {
        'properties': {
            'key1': {
                'properties': {
                    'arr': {'items': {}, 'type': 'array'}
                },
                'type': 'object'
            },
            'key2': {}
        },
        'required': ['key1'],
        'title': 'a title',
        'type': 'object'
    }

